                                        self.switch_on.then_some("switch-on"))}
                                        onclick={link.callback(|_| Msg::ToggleSwitch)}>
                                        { if self.switch_on { "ON" } else { "OFF" } }
                                    </button>
                                </div>
                            </div>
                            <div class="hw-section">
                                <div class="hw-row">
                                    <span class="hw-stat">{"Binary: "}</span>
                                    <span class="hw-stat-val">
                                        { if self.binary_size > 0 {
